(window.webpackJsonp=window.webpackJsonp||[]).push([[51],{316:function(v,_,a){"use strict";a.r(_);var t=a(13),p=Object(t.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("h1",{attrs:{id:"落雪无声"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#落雪无声"}},[v._v("#")]),v._v(" 落雪无声")]),v._v(" "),_("h2",{attrs:{id:"居巢"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#居巢"}},[v._v("#")]),v._v(" 居巢")]),v._v(" "),_("p",[v._v("巢湖，长江五大淡水湖之一，和它的兄弟们——太湖、鄱阳湖、洪泽湖、洞庭湖一样，浩如烟海，无边无际。身临湖滨，湖畔风起，若非少了些许咸腥的味道，恍若身处海岸。")]),v._v(" "),_("p",[v._v("湖滨有庙，是为中庙。庙居湖畔之中，巢湖市与肥东县临近处。据此而观，船舶熙攘，水天相接。纳五文而入寺，虔诚叩首，述心之所困。佛未言，但皆归于不言。言尽于止，缘结于空。")]),v._v(" "),_("p",[v._v("既出中庙，遂西归于包河。过南淝河，遂见滨湖湿地公园。林与水相融，人在其间，天地莫不寂然。间或是溪流与鸟鸣，或有几分禅意。闲居山林，也是一种超脱内卷的悠然。")]),v._v(" "),_("p",[v._v("合肥的旅途即将走到尽头，考研剩余的日子也只有区区五十天了。两串数字，一串是过去，一串是期待。伤透了的过去，已经随着那片叶子从湖心沉入水底，变为湖底的淤泥。辜负了的期待，终究还是应当再从某处重新找回来，不管还能不能追上。")]),v._v(" "),_("h2",{attrs:{id:"实习报告"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#实习报告"}},[v._v("#")]),v._v(" 实习报告")]),v._v(" "),_("p",[v._v("当时间的指针步过了夏天走进了秋天，当金黄的落叶已经洒满了屯溪路校区的校园，姗姗来迟的专业实习才终究来到了我的面前。去之前的我，期待着，却又犹疑着。期待着与旧友的相遇、与都市的重逢，却又因着考研的紧张、前方的迷茫而犹疑。但终究，在这十一月的第一个早晨，我还是踏上了去往合肥的旅途，去面对、去度过，这一段，令人难以忘记的日子。")]),v._v(" "),_("h3",{attrs:{id:"零-初至"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#零-初至"}},[v._v("#")]),v._v(" 零 初至")]),v._v(" "),_("p",[v._v("临近冬天，六点多钟时太阳尚未完全升起，天空是一片藏青色。同行的人们占领了食堂，提着大包小包。考研的人们看着书，但更多的人聊的还是游戏与合肥的种种。大巴车在高速路上疾驰而去，待到合肥已是天光大亮。主教的红楼在略微阴沉的天色背景下更加的庄严肃穆，与楼前喧闹的人声形成了一定的反差。满校园都是扛着全站仪的土木人，他们忙忙碌碌地摆弄着自己也未必弄得懂的仪器，制作着自己也未必明白啥意思的数据。他们有时羡慕着我们所谓的高收入高技术，殊不知我们其实也是一样，敲着自己也难以理解的代码，画着自己也不明白用处的电路。打工人不分高低贵贱，但都不过是卑微的打工人。")]),v._v(" "),_("p",[v._v("收拾完行李便急匆匆地走出大门穿过天桥等待着226路的到来。印象中的226路还是曾经需要从头挤到尾的十八米铰接车，可三号线的开通却让这条线路没有了那么多的客流。单机车在金寨路高架灵活的爬行着，等着旁边的车一辆接一辆驶过。终于赶在十二点上下到了中环城，骑上哈啰小电驴直向合工大的门口行去，在双子楼前等到了来比赛的一群人。题目很难，他们的发挥并不如我曾经般得意，但并没有改变什么结果。验收和答辩拖沓冗长，他们原定的高铁票也不得不改签。他们付出了更多的努力，却也并不能获得比我们当初更加优厚的回报。这或许就是卷吧。")]),v._v(" "),_("p",[v._v("在中环城吃了顿晚饭与他们告别，又只身返回翡翠湖校区，穿过东风广场，看俪人湖的暮色，与如约而至的金老板聊起了未来。绕着翡翠湖的校园走了一圈又一圈，聊着学习聊着生活，聊着合肥与宣城的差距。大家互相羡慕着，但谁也不能变成谁，每一个围城里都有一个方鸿渐，也终会有一个赵辛楣。坐上地铁到达国防科大，骑着小电驴沿着黄山路回到工大老区。简单而复杂，闲适也匆忙，便也是一日。就像临回宿舍前下起的小雨，洗刷了一身尘土，又不至于过大，影响心情。")]),v._v(" "),_("h3",{attrs:{id:"一-蜀山"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#一-蜀山"}},[v._v("#")]),v._v(" 一 蜀山")]),v._v(" "),_("p",[v._v("早高峰的合肥南一环永远都是拥堵的，去往大蜀山的路途更是如此。大巴在车流里挣扎，显得脆弱而无力。就像当人面对着各种错综复杂的事件里一般，可能会崩溃，可能会疯狂。上山的路并不很长，也不曾十分陡峭，但漫长的台阶依然让大家都十分疲惫。秋天的山峰，落叶洒满了山道，颇有几分萧瑟的意趣，而山顶的云雾也让这里的风景变得更加模糊了起来。")]),v._v(" "),_("p",[v._v("发射台二层的平台，是合肥的最高点。依稀能看见不远处的董铺水库，中科大的科学岛便坐落在那里。广电发射台终究只是一个过时的部门，也许它看起来还很光鲜，但也终究逃不脱被时代抛弃的境遇。")]),v._v(" "),_("p",[v._v("在主教里度过了午后的学习时光，困倦的我走出校门，随心向北而去。走过宣城路，穿过包公园，便来到了合肥最繁华的淮河路步行街。恍然忆起，一年多以前，也是在这里，我们一群打完电赛的人在这里度过了愉快的下午。那是暑假已经过半的八月中旬，刚刚结束的大二并没有为我们带来过多的焦虑和忧惧。焦虑是因为不知道自己到底想要做什么，如果很早就定下了自己的目标，自己想从事的行业，自己想爱的人，那么一切其实都没那么急躁，也没有那么跌宕。庐州太太确实不错，但也仅限于家常的不错。啜着温热奶茶，告别繁华，回到工大。")]),v._v(" "),_("h3",{attrs:{id:"二-斛兵"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#二-斛兵"}},[v._v("#")]),v._v(" 二 斛兵")]),v._v(" "),_("p",[v._v("下午档的实习最大的好处，就是可以拥有一个漫长的睡眠。晨起，在校园里走走停停，若不是看教育超市里遍地考研书籍，险些都忘了自己是个考研的人。天气晴好，环绕着斛兵塘转了一圈，秋天的斛兵塘有那么丝明亮的感觉。树影斑驳，水光潋滟，仿佛回到近两年之前的那个冬天，初到合工大，初见斛兵塘。那也是这样一个早晨，天鹅在舞蹈，老人在晨练，一切的一切似乎和那时没有太多分别，唯一的区别只有我自己。")]),v._v(" "),_("p",[v._v("第二天的实习安排是位于遥远北郊的三十头中频广播发射台，高德地图上写作三十头社区电台。看着这个标注，我对这个地方已经有了一定的猜测：大约是一座树立乡间的小房子，上面有一组天线，将远处的信号发射与接收。初到此地，眼前的景象也大约与我的猜测相符。")]),v._v(" "),_("p",[v._v("陈列室里摆放了长久以来的一代代置换下来的设施，比如这里的变压器所需要配备的冷凝器，为了绝缘而必须使用蒸馏水。还有各种林林总总的设施，都是一代又一代人们努力的象征。但发射台的存在本身，就让这里已经落后了几十年。选择未必大于努力，但不选择一定比不努力更糟糕一些。")]),v._v(" "),_("p",[v._v("暮色四合，再一次回到校园里，耳畔是同学们的熙熙攘攘。考试周的焦虑并没有过多影响到大家的心情，斛兵塘边依然是欢声与笑语。又是应当学习的一天，晚安。")]),v._v(" "),_("h3",{attrs:{id:"三-翡翠"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#三-翡翠"}},[v._v("#")]),v._v(" 三 翡翠")]),v._v(" "),_("p",[v._v("从第三天开始，我们参观的单位就变成了合肥大大小小的企业。得益于合肥市政府的大力扶持，一系列半导体企业在合肥生根发芽。比如这家坐落于经开区的中恒微半导体，便是这一轮政策东风里成长起来的企业之一。中微半导体成立于2018年8月，是安徽唯一一家可以独立生产高功率IGBT的SiC芯片工厂。现在已经拥有了2000平米的车间和2000平米的研发办公区域。在细分领域市场中，也是一股不可小视的力量。")]),v._v(" "),_("p",[v._v("这家公司致力解决痛点是能源转换效率和器件可靠性，并且有了一定的技术积淀。在这里，我们可以看见打工人最真实的模样——被禁锢在狭小的工区里，画着晦涩难懂的版图，或者拿着显微镜校验每一块芯片。他们枯燥着，摸鱼着，却又承担着安全生产的使命。相比大公司的机器精校，只能使用人工校验的他们的良率竟然也可以达到98%以上。或许，这就是中国制造，这就是工匠精神。")]),v._v(" "),_("p",[v._v("吃完午饭，主教门口的发车场地已经挤满了焦急等待的老师和学生们。大家排着长队等在车门口，却只等来一句满员勿上。两台大车一台接一台地开走了，只留下最后一台车留给大家唯一的希望。可司机点完了老师的数目，又默默地从剩下的座位数里扣减了一个数，然后才告诉排队的我们，只有十个座位。幸运的是，我排在前十之中。当我还在回味车下人悻悻的目光时，我已经站在了双子楼前。想来这可能是他们长久以来的记忆，我又些许释然了。")]),v._v(" "),_("p",[v._v("下午的学习时光悠然而宁静，翠十二教、翠十教、翠八教里成排的空教室欢迎着我的到来。随便选了一个看上去不错的教室，再出来的时候便已经是黄昏时分了。秋天的傍晚，俪人湖畔的东风广场，夕阳西下，别有几分意趣。有人在双子楼实验，有人在翠七教学习，还有更多人在图书馆里辛勤刻苦耕耘着。他们努力，他们奋斗，他们充实。他们为着他们美好的明天和未来而奋进着，为着他们看起来朝气蓬勃的明天而奋进着，我羡慕着，却又无可奈何。")]),v._v(" "),_("p",[v._v("夜色里，骑上电瓶车融入合肥的风里，正大广场的摩天轮依然树立，让我想起了那个深夜里的大雨。沿着金寨路缓缓走行着，便到达了合柴1972创意园区。监狱改造了人们，人们也改造了监狱。这曾经的监狱高墙，画上了充满艺术的涂鸦。就像北京的798，南京的1865，这里也成为了一个现代艺术的集中地。不过，合肥终究也只是合肥，它的人文并没有跟上它的经济。这样一个街区的存在，也不过如此而已。")]),v._v(" "),_("p",[v._v("继续前行，向东拐弯，不久便看见了出现在眼前的罍街。这是合肥的又一条繁华闹市，但熙攘的人流比起淮河路还是稍有逊色。然而旁边的一切都还是正在建设的模样。未完待续，让这里有着更多的可能，旁边的城中村都显得并没有那么破落。沿着宁国路北上，合工大又一次浮现在了眼前。在这个夜里，风也温柔，你也温柔。我曾以为，做不成恋人，便也做不成朋友。因为内心的懵懂，头脑的冲动。但似乎，也并不尽然。")]),v._v(" "),_("h3",{attrs:{id:"四-巢湖"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#四-巢湖"}},[v._v("#")]),v._v(" 四 巢湖")]),v._v(" "),_("p",[v._v("最后两天，我们参观的是两家规模庞大的上市公司，他们分别在自己的领域里做到了十分可观的高度，所展现出的技术实力也使我们心动和叹服。第四天的行程，我们去的是经开区西郊的四创电子公司。四创电子作为中国电子三十八所旗下部门所独立出来的单位，依托三十八所的一系列技术，做出了许多令人惊叹的东西，从高精雷达到智能生活，从军事领域到民用科技，他们所生产的产品都有所触及。")]),v._v(" "),_("p",[v._v("展览馆里陈列的则是一系列他们公司为工业现代化做出的努力，从智慧园区到智慧城市，从智能交通到智能安防。万物互联，让生活更美好，也让生活更加的惬意。")]),v._v(" "),_("p",[v._v("午后的B7路缓缓驶出周谷堆，沿着南北一号高架与包河大道一路疾驰而去，不久便来到了滨湖新区。姗姗来迟的308路则带上了一车人去往三十公里外的巢湖中庙。中庙居巢庐之间，被赞为所谓的“湖天第一胜境”，庙前看湖，湖深似海。身临湖滨，又仿佛身在海边，心情豁然开朗。佛祖并不能帮助我们什么，也并不会要求我们什么。他什么也不会说，但却又什么都说了。")]),v._v(" "),_("p",[v._v("包河区紧邻长临河的滨湖湿地森林公园则又是一番景象，这里宁静而安详，蝉鸣鸟叫，泉水溪流。林深处的一抹火红色，与满园苍茫的绿形成了鲜明的反差。就像那人群里最耀眼的一颗星。我可以一时之间沉醉，却不能一直沉迷。人终究还是要选择前进的，无法在一处，长久流连。会错过，会后悔，但只要她幸福了，这一切，又能如何？")]),v._v(" "),_("h3",{attrs:{id:"五-临归"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#五-临归"}},[v._v("#")]),v._v(" 五 临归")]),v._v(" "),_("p",[v._v("一晃，短暂的旅途就要走到终点了。也许还有想见而未见的人，但或许并没有太多必要去见了。洗个澡、理个发，静静等待着最后一天的过去。似乎并不圆满，却又似乎又很圆满。心中的结有了那么一丝松动的征兆，而所谓的梦想似乎也没有预想的那么遥远了。或许，这便是这趟旅途对我来说最大的意义。")]),v._v(" "),_("p",[v._v("最后一天的行程，是北京兆易创新合肥公司的开放日活动。作为一家主攻MCU和Flash方面的企业，这家公司在集成电路领域颇具建树。兆易创新的手机存储芯片和32位单片机，在国产产品之中都是行业领先的品牌，与中芯国际等公司也有深度的合作，这吸引了我浓厚的兴趣。随后公司又介绍了许多关于薪资和培养方面的细节，他们的企业文化和高报酬也让我十分艳羡。所以其实，考研，真的有那么必要吗？")]),v._v(" "),_("p",[v._v("2020年10月16日，北航微电子学院更名为北航集成电路科学与工程学院。这样一个普普通通的名称更迭，并没有掀起哪怕一点点波澜。微电子或是集成电路科学，本质上并没有太多的区别。但或许，国产集成电路，还拥有着还不错的未来。")]),v._v(" "),_("p",[v._v("老区食堂的螺蛳粉和北门的生煎，还有东门外的烤冷面或者卷面皮，味道都相当的不错，但也终究不过如此。我们可以品尝很多的小吃，但终究比不上正餐。我们可以在花丛中流连，但我们终究只能喜欢一个人。")]),v._v(" "),_("h3",{attrs:{id:"六-离别"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#六-离别"}},[v._v("#")]),v._v(" 六 离别")]),v._v(" "),_("p",[v._v("当校车最终驶出了校园的北大门，汇入周六一大早出城的车流中。这一趟不算圆满也不算遗憾的旅途也算是了结了。单身诅咒依然发挥了它应有的作用，又一个见到的朋友在这一周里结束了单身的生活。但既然已经知晓，那便已然看淡。最后半年了，就算真的有一个合适的人出现，我依然还是会在纠结中放弃，就像之前无数次那样。")]),v._v(" "),_("p",[v._v("爱若执炬迎风，炽烈而哀恸。诸般滋味皆在其中，韶华宛转吟诵。不得不承认，为情所困是个多么理想的理由。浪漫而凄惨，悲伤而壮烈。不论究竟是多少种压力使得人走上了绝路，为情所困终归是一个理想的理由。成年人的压力四面八方，没有人知道什么会是那最后的一根稻草。分不清现实与梦的岁月才是最好的岁月，可以把好的一切当做现实，而把不愿接受的一切当做是梦，即使实际情况完全相反。")]),v._v(" "),_("p",[v._v("考研的本质不是一种梦想或者压力，而是一种纯粹的幻想和逃避。自始至终我也没有想过真的能够上岸，但也从来不曾彻底放下过考研的进程。失去的东西，在它失去的那一刹那，它就已经回不来了。可初心丢掉的那一刹那，我上岸的概率，却前所未有的高了起来。起码，我愿意相信，我现在要是能够上岸，并不完全会是一个奇迹。")]),v._v(" "),_("p",[v._v("但与此同时，上岸和表白也没有了任何的关联。既然上岸已经不是一个奇迹，那建立于奇迹发生的条件之上的表白，也不再有任何一点实际的意义了。")]),v._v(" "),_("h3",{attrs:{id:"后记"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#后记"}},[v._v("#")]),v._v(" 后记")]),v._v(" "),_("p",[v._v("回到宣城的第二天，随着实习报告的完结，这一趟秋日的旅途也算是画上了一个不算特别圆满的句号。给新生的培训课堂上，终究没有看见那一抹影子，或许，是她也不敢再面对我了吧。这样其实也好，对谁都好。")]),v._v(" "),_("p",[v._v("不过，我还是想去写上一篇真正的实习报告。")]),v._v(" "),_("p",[v._v("然而，如果我现在不是大四，我还会有勇气吗？其实大概率还是没有的。")]),v._v(" "),_("p",[v._v("还剩四十八天了。")]),v._v(" "),_("p",[v._v("或许，我需要一种完完全全的自闭。")]),v._v(" "),_("p",[v._v("但也未必会有多少意义。")]),v._v(" "),_("h2",{attrs:{id:"胡言"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#胡言"}},[v._v("#")]),v._v(" 胡言")]),v._v(" "),_("p",[v._v("直到看见了23:00还没有熄灭的灯，我才意识到，又一个周末就这么悄悄地接近了。")]),v._v(" "),_("p",[v._v("这一次关闭空间的理由，和上一次大不相同。在那一场内卷人的狂欢之后，专业同学里少了许多的戾气，多了更多的和谐。保研是属于圈内人的卷法，而考研是与未知对手的较量。大家终于少了那么多的人身攻击和戒备，开始安心于自己的生活。少了各种各样的攻击，似乎也没有了关闭空间的理由，但是，我还是关了。似乎是自身的戾气越来越重，但终究是不想有意或无意伤害到本来可能是对我心存善意的那些朋友们。")]),v._v(" "),_("p",[v._v("从合肥回来之后，一切都好像完全变成了风轻云淡的样子。时间无非只是早八和晚十的周而复始，上午是数学下午是英语或者专业课，晚上看看政治或者去实验室打开电脑摸摸鱼。相对而言，数学令我比较慌张，但英语可能更加狼狈。不过不知道是战线拉的太长还是先期的目标设定过高，现在的我并没有别的考研人那种正常的紧张和单纯关注学业的焦虑。时间似乎一直都很充裕，因为我这结果跟时间并不是什么比例关系。我可能比他们更焦虑，但焦虑与考研本身不太相关。")]),v._v(" "),_("p",[v._v("秋冬季常有的鼻炎在这个特有的季节里悄然回归了，情理之外而意料之中。毕竟有这么个病根一直存在着，只不过三年没有发作而已，并不意味着它就彻底好了。但为什么第四年会重新发作嘛，自然是因为目前不健康的生活以及焦虑的心态。大一坚持每周末都要去爬山，大二学业繁重每天在校园里高强度游走，大三则是三天两头往返在206省道上的十公里路途，而大四只能每天在新安的自习室里掉落着头发。焦虑意味着烦躁和过量饮食，意味着熬夜和减少锻炼。我没有太多的信心和期待，甚至愧对于加油鼓劲的朋友们。")]),v._v(" "),_("p",[v._v("有人会觉得我可能可以做人生导师去对他们进行开导，但是我少了一种人生导师所必要的正能量。知道的太多反而不会快乐，活的太现实也就会过于卑微。大一开始时的我很快乐，那时的我喜欢历史和地理，会去追寻某一段历史背后的真相，争论一个人物的是非功过；会去看某一地方的规划图纸，品味一个地方的风土人情。那时常常看书，看人物传记，看小说散文，代入人物的生活细节，去品味不一样的人生态度。也热衷水群，但并不频繁的玩梗，也不会特别去关注于时事。那时的社会里天坑一词尚不常见，内卷一词更无从耳闻，只有贸易战作为一抹阴影笼罩着，但前途依然是光明的模样。")]),v._v(" "),_("p",[v._v("那一切是什么时候开始变化的呢？我也不知道。随着那片叶子尖利地划破心口落入湖水的深处，曾经阳光的一切渐渐起了一层阴霾。电信科带着它无尽的压力向我冲来，把所有的塔全部推倒，连同着爆破了高地上的水晶。我消沉了，放弃了，可外部的环境却也急转直下了。内卷的风暴渐渐卷起，生化环材的天坑变得耳熟能详，机械土木的提桶跑路成为了常态。所有的工科似乎一瞬间都没有了前途，每一行都指向着CS的终点，而身在计算机院之中的人却感受到了实实在在的压力。高薪伴随着加班和猝死，却依然是大家可望而不可即的去处。软件和算法似乎是信息类唯一的出路，不懂Coding几乎等于不懂一切。但事实真的是这样吗？")]),v._v(" "),_("p",[v._v("幸运的是，在这样一个时刻里，我走上了一条卷的不那么透彻的路，来到了一个氛围十分友好的实验室里，并以最快的速度，练就了一门单片机的技术，并在这条路上逐渐树立了些许的口碑和声望。反复研读的全新版本内卷指南向我指出了一条尚不曾为大多数人所关注的道路——竞赛。而如今这条赛道却已被卷王们塞的人满为患。我试图挣扎了一阵子，可是在那个夜里的反复计算之后，我终究失望地意识到，这条路我依然走不通。")]),v._v(" "),_("p",[v._v("那么既然考研无法避免，那便彻底地转向CS吧。专业课除了微机原理和计算机网络都没有了什么太大的必要，那么就随便学学能过就行。羡慕于敢于抛弃一切去追寻理想的同学，但是我做不到，因为我并没有什么理想。大约也就是这个时候开始，我的日子逐渐过的浑浑噩噩，不敢去想未来去做什么，也不敢去面对真实的未来。道理我都懂，但我就是做不到，所以说我不配当任何人的人生导师，哪怕是我自己的。")]),v._v(" "),_("p",[v._v("一件事情有没有意义，取决于他对你的目标有没有帮助。一件事情如果不能达成或者偏离了其既定的目标，就可以算做没意义。我的初期目标是为下一阶段进行一个充分的铺垫，并获得一项值得为之努力的目标。目标是获得目标，本身构成了一种嵌套，无止尽的递归嵌套，结果就是一个死循环。我永远也找不到我寻找的东西，并扭成了一个彻底的死结。这个死结一直伴随着我大学三年，伴随着我的一切，直到现在，也会持续到未来。")]),v._v(" "),_("p",[v._v("在牛头冲这片不大的天地里，我曾经有过许多的朋友，却又几乎没有朋友。当我意识到某一种亲近关系可能已经走到了尽头的时候，我会清空关于对方的一切，最终沦为彻底的陌生人。其实有一个仪式感的道别，总比有的人走着走着就散了来的好吧。没有仪式感的道别，那种感觉就是突然在什么地方看见一个很熟悉的名字，然后想想发现自己曾经跟他那么熟啊，然后就没有然后了。渐渐地，朋友们大多就都没了声息，然后一个接一个消失在列表里。QQ好友230个，常规的可见分组里193个，真正算得上是朋友的，或许真的没那么多。而即使是真正的朋友，有时候也总让我分不清，到底是一种什么样的感情。")]),v._v(" "),_("p",[v._v("所有的感情问题，大多也不过是自己给自己加的内心戏而已。就像死结之中其他的一切一样，都不过是属于死结本身的一部分。我内心里的她，总是似乎没有任何缺陷，完美的高攀不起。她似乎应当是那个我值得为之努力的目标，却又不是。那么这么来说，如果对方是那个值得的目标，对方就一定会拒绝配不上对方的我，如果不是，那么我就应该去拒绝不是目标的对方。这就形成了十分奇怪的逻辑回环，在陷入这个逻辑回环之后，就会犹疑，会搪塞，直到失去或者错过，才反而像是符合了这个循环应有的逻辑，继而心安理得。但真实的情况，已经无从得知了。")]),v._v(" "),_("p",[v._v("似乎，我现在的样子，很像是一个技术水平还不错的打工人。但是，做技术从来都不是我的爱好，它更像是一种被迫的手段。策划，组织，协调，教学，甚至是写稿，有时候都会给我带来比单纯的解决技术问题更多的快乐。可问题在于，喜欢和擅长从来也不是一回事，我喜欢的事物，我多半并不擅长，而我擅长的事物，我不一定喜欢。")]),v._v(" "),_("p",[v._v("读书(可能也包括电影和音乐)和旅行(可能也包含登山骑行等户外)似乎是一以贯之的爱好，但也与大多数人所认为的读书和旅行并不相通。读书更多在于体味书里的情感和意境，或者是投入其本身的情节与感动，而旅行更多时候则是把虚幻的地图印证为实体，把地图上星星点点的位置对应出其映像之中的场景。城市公交的车辆调度，地铁线网的架设规划，铁路车站的枢纽布线，老城新区的路网布局，城市之间的行政交接，铁路运输的布点排图，最终都通过一次一次的实地走访，变成了记忆里最真实的模样。")]),v._v(" "),_("p",[v._v("但终究，这并不是什么大众的爱好，也并没有多少与之足够相关的职业。于是，爱好终究便只能是单纯的爱好，无法成为理想。既然终究也没有理想，那便还得在现实之中浮浮沉沉，在彻底的死循环里，将这永远也解不开的结，持续下去，直到人生的尽头。")]),v._v(" "),_("p",[v._v("所以现在又横跳去微电子，虽然也不知道去不去的成。IC并不是一个足够有前途的行业，起码目前不是。就像我并不是一个足够有前途的人，起码现在不是。")]),v._v(" "),_("p",[v._v("终究也不过是半夜的胡言乱语罢了。。。")]),v._v(" "),_("h2",{attrs:{id:"智能时代"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#智能时代"}},[v._v("#")]),v._v(" 智能时代")]),v._v(" "),_("p",[v._v("似乎机器学习和人工智能确然是一个很老的概念了。机器学习的本质是数学，但机器学习的算法大多历史悠久。机器学习在现代的快速进步得益于设备性能的提升和海量的大数据。如今的机器学习是一个纯粹的工程学问题，目的是更好的实现指定的效果。而大多数时候，真正想要提升模型的精度，依然需要的是喂给越来越大的数据集。")]),v._v(" "),_("p",[v._v("机器学习的大发展本质上还是归因于大数据的应用。本质上机器学习可以算作是数据挖掘的一部分，使用机器学习手段进行数据挖掘以获得更多信息，这也正是我这么多年以来所热衷于去做的。通过大数据的分析与处理得到一个数据库，并使用之获得一些十分有趣或者十分有用的东西。此外，在这个过程中，我也get了一套比较完备的信息检索方法，能够在较短的时间获得一些有用的东西。似乎这可能也是有那么一部分人觉得我百事皆通的原因之一。")]),v._v(" "),_("p",[v._v("大学时光已经过去了三年半。这三年半里我结交了不少朋友，虽然也失去了更多。如今所留下的朋友大多具有某些特定的意义，他们所组成的网络可以让我相对方便快速的达成某种目的或获得某些急需的信息。通过这样的网络以及之前所建立的数据库我帮了许多人的忙，也给自己带来了许多方便，但也为我招致了相当程度的不满。大数据一方面意味着便捷，但另一方面就意味着隐私的丢失。我获得了一套完备的数据，我利用其解决了一些问题，但涉事的人也会觉得自己的隐私受到了严重的侵犯，他同样不会给我好脸色看。许多朋友就这么失去了，我也没有办法。")]),v._v(" "),_("p",[v._v("举一个例子，通过三年公示的奖学金成绩进行运算就可以方便快速的获得一份相对准确的保研成绩排名。这甚至算不上是大数据，但这样的内容无疑会在保研关头使得很多人心烦意乱，甚至一定程度上会影响大家对竞争对手的判断，通过对加分等过程动一些手脚来改变保研结果。看起来数据的利用确然不是什么大事，但这样的内容流传确实会引起一些难以估计的后果。")]),v._v(" "),_("p",[v._v("第二个例子是考研期间公示在每个考场门口的考生信息表。表上只有每个人的姓名和准考证号。看起来这个数据平平无奇，但是如果将姓名与2017级的学生名单进行撞库，就可以很轻易的得到各自的报考信息。考虑到考研准考证号的编号具有很强的规律性，我们甚至可以通过公开途径的学院编号等信息来直接得到该同学报考的学校、学院甚至是专业。这并不是什么难事，甚至只要几分钟就能搞定，但是从某种意义上说严重的侵犯了隐私，也会引发当事人强烈的不满。")]),v._v(" "),_("p",[v._v("每个人都有一种与生俱来的窥私欲，对他人信息的渴望在这个大数据时代里变得极其容易。活在数据里的人曾经往往生活在黑暗里，不得光明。而如今他们拥有了各种光鲜亮丽的头衔，出没于A厂T厂之间，千方百计为资本寻找韭菜最后的归宿。这么多年了，我也不再是曾经那个我了，对数据的热情和窥私的热衷早已不复从前。相比A厂，我可能更喜欢T厂一些，因为A厂对数据的滥用毫无底线，而T厂好歹还会留下一点尊严。")]),v._v(" "),_("p",[v._v("但总的来说，对于软件业，我或许已经有了一些厌倦了。无休止的加班只是为了无休止的割韭菜，当镰刀割尽了韭菜，自己也就成为了韭菜。大数据为每个人精准定制了一把独属于他们自己的镰刀，热衷于购置高价消费品的管他叫消费主义，无奈不得不贷款买房买车的人管他叫社会压力。无论如何，每个人都逃不过一把镰刀，无论是韭菜还是割韭菜的人，都会被收割。迷茫和困惑是这个时代的主旋律，我可能没有完全丧失奋斗的热情，但我还是想要去寻找一个我热衷而且感兴趣的事业。或许，没有事业，感情也行。")]),v._v(" "),_("p",[v._v("但我同样不可能拥有美好的感情。黑暗里的人，习惯了用影子中的视角看待一切，早已学不会光明磊落的做事。我总是想要了解关于我所喜欢的人的一切，总以为自己可以接受一切，但最后还是失望的叠加和落寞。也许并不是我运气差到每一个喜欢的人都并非良人，只不过当我有机会去审视关于她的一切时，她就已经不会再像我想象的那么美好了。一切的一切基于的信任在大数据面前一触即溃，当信任消失，什么也都消失了。")]),v._v(" "),_("p",[v._v("刚刚做了一个测试。在激情、爱情、家庭、事业和金钱五者之间，我发现我潜意识里首先会将金钱置于中间位置，而将事业置于金钱之后。而对于剩下三者，我的排序则甚是模糊。也许测试之中面临的困境也就像我现实所面临的困境一样。测试本身的内容有失偏颇，我更看重的可能是自己所投入的爱情，而在其中所反映的却是家庭。我并不知道如何去处理一种对方一厢情愿的感情，或许是从来没有过，也或许是我刻意的视而不见了。逃避永远是任何问题的当下最优解，但也永远是长期最劣解。")]),v._v(" "),_("p",[v._v("我是一个过于感性的动物。数据的刻板和理性总能影响到我的感性，以至于在感性的催化下做出足够多的不理智决定，这也注定使得我不会成为人群里2%的佼佼者。从直面市场的经济金融退到身居幕后的电子信息，再而有可能走向籍籍无名的芯片产业。我拥抱这个时代，却也逃避这个时代。")]),v._v(" "),_("p",[v._v("读吴军《智能时代——大数据与智能革命重新定义未来》，结合近期发生的各种事有感。")]),v._v(" "),_("h2",{attrs:{id:"城市回忆"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#城市回忆"}},[v._v("#")]),v._v(" 城市回忆")]),v._v(" "),_("p",[v._v("在各大城市地铁尚未成网的十年之前，公交是大家出行的最好交通工具。一条历史悠久的公交线路，是城市的名片，承载了许多人悠远的回忆。但随着地铁时代的来临和城市拥堵的加剧，越来越多的公交线路或是退出了历史舞台，或是以一种其他的方式延续着自己。")]),v._v(" "),_("p",[v._v("2021年2月6日，北京公交701路改名为4路。消失12年的4路路号重启，也意味着20余年的701路乃至整个7字头号段走向了终结。还记得遥远的十多年前，北京奥运时代，长安街上还是1路4路52路御三家的天下。马官营-四惠，靛厂新村-四惠，以及北京西站-平乐园。拥挤的18米通道车上，售票员扯着一口京片子报站。尽管已经有了电子报站，但多数时候还是靠售票员喊。那时候北京市区公交刷卡还只要四毛钱，地铁任意两站不过两元。")]),v._v(" "),_("p",[v._v("后来很快由于1路和4路全程重合，1路并入了4路，新的神州大一路起点站变成了靛厂新村，而4路从此消失，直到12年后重见天日。长安街上多了99路728路等等，又逐渐消失并入长安街双雄。几经变更后的1路变成了老山到四惠，而公主坟到靛厂新村变成了52路的线路。分段计价的公交逐渐失去了对地铁的价格优势，只留下天安门前红蓝两色的风景。")]),v._v(" "),_("p",[v._v("大约12年前后，外婆一家搬到了东四环外的望京，701路从此映入眼帘。车辆进站，请注意安全，乘客您好，701路公交车开往，大西洋新城南门。701和运通101，穿北京城而过，起自东北，终到西南。而今它们都以新的身份活了下来，一个变成了4路，另一个变成了921路。它们算是幸运的，还有更多的线路，在一次又一次的截线撤线中彻底的消失了，比如420(望京科技创业园-北京站东)，比如131(东直门-望京科技创业园)。")]),v._v(" "),_("p",[v._v("而在其他的地方，同样的事也在发生着。2013年，南京老5路(莫愁新寓-柳营)撤线，163路更名为5路，从此5路不再是曾经的5路。当时初中的我，还特意去赶在最后一天乘坐了一次5路，也算饯别。2018年去苏州西山时还曾乘坐过的69路(火车站-石公山)，在2019年就变成了快线11号，随即在2020年缩短到了木渎，与691几乎全部重合，濒临停运。")]),v._v(" "),_("p",[v._v("如今，坐公交的人比起曾经减少了太多太多。城市的发展速度让公交很难再跟上城市发展的脚步。长线截短，短线截无，频繁改线，让更多人不再依赖于公交出行。就像高铁时代的我们也渐渐忘却了曾经的绿色25B红色25G蓝色25K白色25T，而以统一的名词绿皮车来代指这一切垂垂老矣的机辆列车们。")]),v._v(" "),_("p",[v._v("或许，这就是不可违抗的时代大潮吧。")]),v._v(" "),_("h2",{attrs:{id:"新年快乐"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#新年快乐"}},[v._v("#")]),v._v(" 新年快乐")]),v._v(" "),_("p",[v._v("又到了一年一度的璃月港海灯节(×)中国传统农历春节的时候了。")]),v._v(" "),_("p",[v._v("过去的十五年里，我有明确印象在南京度过的春节，不到五个。为什么会很少在南京过年呢，一大因素就是亲戚特别特别少，以致于会有那么点无聊的感觉。南京禁放烟花爆竹似乎也有七八年了，比较冷清的家里，大家看着无聊的节目，似乎也就这么回事。")]),v._v(" "),_("p",[v._v("上一次在南京过年的时候，好像还是五年前。对上次过年最大的印象好像是年三十的夜里，从理工大里奶奶的老房子走回秦淮区这边的家，一路上数着一座座小区里点亮的灯火。星星点点的，大约一小半吧。此外似乎就没啥了，一切都平平无奇。")]),v._v(" "),_("p",[v._v("那年好像是要小高考了吧，寒假安排我们去南大补习小高考科目。好像下过一场挺大的雪，坐车路过紫金山里，漫山遍野银装素裹，煞是好看。我喜欢这雪，但也知道这雪终究要化。大约也像是我当时有过的一点卑微的喜欢，喜欢隔壁班的那个整天欢欢乐乐的女孩，却知道永远也不可能有结果。")]),v._v(" "),_("p",[v._v("看起来感情是我生命中十分珍贵的一部分，但是珍贵的前提其实是稀少。我的感情总是淡薄而疏远，顾虑多于执着。但偏生我又是一个感性重于理性的人，多数时候被这稀薄的感情所控制、所影响着。非理性状态下的我，是我自己都难以理解的我。")]),v._v(" "),_("p",[v._v("来到大学的我，一开始想寻找的，其实是她的一面镜子。一厢情愿的我，依然觉得，只要能找到一个她在这里的投影，似乎一切就应该会是顺理成章的。但后来的事告诉我，这样一个光芒四射的人，她不会成为一个能够保护你的人。她的人生会很精彩，但却无关于你的无奈。")]),v._v(" "),_("p",[v._v("于是，我怀揣着我碎裂的前程和梦想来到了珠海。在这座南国的小城里，骑着车看着海，逐渐释然了心态。我认识了越来越多的人，也因着各种各样的机缘巧合而萌生好感。有的是有距离感的好感，作为朋友的喜欢与感动。有的是没有距离感的好感，作为兄弟的亲切与陪伴。我珍惜这样的感情，却很难维系这样的感情。很多感情变质了，但更多的感情，走散了，再也看不见了。")]),v._v(" "),_("p",[v._v("诚然有一部分的异性朋友，我打认识开始就有了些别样的想法。但对于绝大部分的朋友，感情都是慢慢才开始变质的。变质的感情不一定不可延续，漫长的时光也有可能会回复到未曾变质的模样。但更多的，只能无力地消散。")]),v._v(" "),_("p",[v._v("渐渐地，我也忘了什么是喜欢的感觉。我只知道，凡是我起了心思想要去追求的人，总会在第一时间与另一个更值得的人脱单。直到我遇见那个，陪伴了我大半个2020的人。我以为我找回了喜欢的感觉，却只是一场属于我一个人，不，一只小丑的马戏。我以为我可以一直等下去，可我终究还是接受不了一个属于我厌恶的人的结局。")]),v._v(" "),_("p",[v._v("也许我真的应该认清自己，认清自己不配也不能去喜欢任何人的现实。最后半年了，回想我的大学生涯。似乎除了充实，更多的还是滑稽。我喜欢的人，值得更好的人；我等待的人，配不上我的等待。而我自己，只配单身。")]),v._v(" "),_("p",[v._v("于是纵使想过千言万语，也只会也只能变成四个字：")]),v._v(" "),_("p",[v._v("新年快乐！")]),v._v(" "),_("h2",{attrs:{id:"唐探三"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#唐探三"}},[v._v("#")]),v._v(" 唐探三")]),v._v(" "),_("p",[v._v("总共136分钟的剧情，我感觉我可以给到一大半的4星和一小半的3星，但是合并在一起大约只能给到2星。想要在一部片子里讲两个故事，却缺乏足够的铺垫与衔接。要是去掉后面那一段，单纯讲好第一个故事，或许这部剧会比现在所呈现出来的好太多。")]),v._v(" "),_("p",[v._v("(当然作为一名lsp长泽雅美那么好看怎么能是反派呢还是一个身世那么惨的反派我这虽然可以理解但不能接受啊喂)")]),v._v(" "),_("p",[v._v("4星给Q的剧情，虽然略显老套但依然表现的很好，有笑点也有思考。依然是传统的精英凌驾于他人之上的剧情，继续试探人性的弱点，人性的恶毒。对主角的重重考验被主角一一闯过，试图收买身陷囹圄的主角被坚决拒绝并巧妙反转。如果故事到此作为结局，哪怕小林是Q的一枚棋子，似乎剧情也更为顺畅，我从情感上也更能接受些。")]),v._v(" "),_("p",[v._v('我们不是所谓的精英，我们从来也不会也不能凌驾于所谓的愚人众之上。即使哪一天我们成为了愚人众执行官，我们依然只是广大愚人众的一员，一名普普通通的"公子"或者"女士"。我们不是神，也从不妄想成为神。即使是神也知道，长治久安的社会不能完全依靠神的能力，更应该依赖于契约的精神，法律的精神。就像海灯节的美丽，不是神所能赐予的，而是每一个平凡人愿望的结晶。')]),v._v(" "),_("p",[v._v("3星给小林和渡边的感情戏。作为这个故事实际上的主线，令人发指的抛妻弃女与被抛弃的母女俩悲惨的遭遇也是一个很大的话题。但匆匆铺垫的背景和匆忙反转的让这个故事硬生生的被写烂了。综合2星则是因为，杰克贾的东北剧情细想之下完全不值得推敲，唐仁的泰国之行仿佛也只是为了让该出场的人出个场，硬塞的人物背景分外生硬，法庭最后一段的感情戏也有一种毫无铺垫直接高潮的尴尬。如果这一段的剧情能够稍微自然一点，或许这部片也不至于被很多人吐槽成这样。")]),v._v(" "),_("p",[v._v("但若是单从这个故事的主线而言，渡边在日本艰难起步难以为继，最终为了自己与父亲进行了交易，抛弃了妻子和女儿，让妻子为了生存去偷去抢去卖，让女儿没有父爱以致于轻易的委身于邪恶大叔。如果是我们，面临这样的际遇，又会作何选择呢？是继续带着妻女艰难打拼还是为自己博一个光明的未来呢？")]),v._v(" "),_("p",[v._v("我不希望有朝一日，我所爱的人，会因为我的缘故而受尽苦难折磨。也许曾经的我还是期待着会有一个强大的人能关爱我保护我，但如今的我，开始期待能有一个人，是我所可以保护的。我期待我能够强大到可以保护我所爱的人，可现实的我还是太弱了，弱到我自己都不相信我能照顾好谁。人生中第二十一个单身的情人节过去了，晚安。")]),v._v(" "),_("h2",{attrs:{id:"适度喜欢"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#适度喜欢"}},[v._v("#")]),v._v(" 适度喜欢")]),v._v(" "),_("p",[v._v("夜里做了一个很长很长的梦，梦里的一切，都特别的真实又不真实。不知道是不是处女座的一种奇怪的弊病，我很多时候会过于苛求细节的逻辑完备，试图营造一个绝对符合真实的场景。于是当我试图写小说时，总会为交代背景而困扰，而论述也会因此而篇幅过长以致于趋近无聊。于是渐渐的我只写些散文和散文诗，不需要逻辑，只需要手就行。")]),v._v(" "),_("p",[v._v("我一直都清醒的认识到，我对异性的情感是有边界的。朋友，好感和喜欢，不同的情景决定的不仅是情感本身，还有一切行为和处事的边界。在朋友的情景下，一切的关联是脆弱的。我不会去掩饰任何情绪上的波动，甚至会频繁使用冷暴力(我不是很擅长语言暴力)。这种情况下，我不会考虑去与之主动组队从事任何活动。我害怕，我会因为绝对意义上的非理性冲动，一气之下撂挑子不干。")]),v._v(" "),_("p",[v._v("好感，也就是所谓的友达以上恋人未满。好感的本质是一种一厢情愿，明知不可能故无所作为，因而最终只能感动自己。这一类朋友可以说是我情感之中最珍重的人。很少，准确的说应该就六个，但每一个都很重要。尽管大多数其实长久不联系，但偶尔看到她们的消息，也会由衷地欣喜。她们是我列表里最优秀的一批，卑微如我，自是不敢有所妄想与希冀。任何情况下我都不会对她们生气或者发火，甚至一点不好的想法都不会有。我会永远相信她们，永远。")]),v._v(" "),_("p",[v._v("还有的人，可能在还没有过多接触之时就已经喜欢上了，也就是所谓的一见钟情或者一念倾心吧。这也许不是真正的喜欢，只能算是一种欲望吧。有的人就是很善于去唤起我这种欲望吧，虽然应该不是刻意，但就是让我这样的人很容易被吸引。但既然只是欲望，那渴求而无所得之后便很容易走向其他的极端。也许是陌路之人，也许连陌路之人都算不上了。感情支配下的我丧失了大半的智力，甚至比不上一个正常人。这也就是一旦我沉溺于感情，就必然诸事不顺的原因。不过人类总是学不会吸取教训，俺也一样。")])])}),[],!1,null,null,null);_.default=p.exports}}]);